import { useState, useEffect, useRef, useMemo } from "react";

const SEED_MODELS = [{"id":"cap-theorem","name":"CAP Theorem","category":"tradeoff","first_principle":"In a distributed system, you can only guarantee two of three properties simultaneously: Consistency, Availability, and Partition Tolerance.","derived_from":"Fundamental limits of network reliability and synchronization","when_applies":"Designing distributed databases, microservices data stores, or any system where multiple nodes must agree on state","when_breaks_down":"Single-node systems; when partition tolerance isn't required (e.g., systems on a single reliable LAN)","ai_application":"Vector databases and embedding stores face CAP tradeoffs \u2014 eventual consistency in a multi-region Bedrock Knowledge Base can return stale embeddings during partition events","connects_to":["eventual-consistency","fallacies-distributed-computing","two-generals-problem"],"tags":["distributed-systems","databases","consistency"]},{"id":"conways-law","name":"Conway's Law","category":"emergence","first_principle":"Systems mirror the communication structures of the organizations that build them.","derived_from":"Organizations optimize for internal communication paths; software boundaries emerge along team boundaries","when_applies":"Designing microservice boundaries, API contracts, team topologies, or any large-scale system with multiple teams","when_breaks_down":"Small teams building small systems; when strong technical leadership overrides org structure intentionally","ai_application":"AI agent boundaries often reflect team ownership \u2014 an 'asset agent' owned by one team won't naturally share context with a 'workflow agent' owned by another without explicit integration design","connects_to":["chestertons-fence","second-system-effect","leaky-abstractions"],"tags":["org-design","team-topology","architecture"]},{"id":"chestertons-fence","name":"Chesterton's Fence","category":"cognitive","first_principle":"Don't remove something until you understand why it was put there.","derived_from":"Survivorship bias + accumulated context; the absence of visible failure doesn't mean no protection exists","when_applies":"Refactoring legacy systems, deprecating APIs, removing 'dead' code, simplifying prompt chains","when_breaks_down":"When original builders were provably wrong; when context has fundamentally changed and the fence is now actively harmful","ai_application":"Don't strip 'redundant' guardrails in a system prompt without knowing what failure mode they were preventing. That extra instruction probably exists because Claude did something unexpected once.","connects_to":["second-system-effect","local-global-optima","survivorship-bias"],"tags":["refactoring","risk","legacy-systems","prompting"]},{"id":"leaky-abstractions","name":"Leaky Abstractions","category":"failure","first_principle":"All non-trivial abstractions leak \u2014 the details they hide will surface at the worst possible moment.","derived_from":"Joel Spolsky; abstraction layers cannot eliminate underlying complexity, only defer it","when_applies":"Choosing frameworks, ORMs, managed services, or any layer that hides implementation details","when_breaks_down":"Truly thin wrappers with no hidden state; simple pass-through adapters","ai_application":"Bedrock Knowledge Bases abstract chunking, embedding, and retrieval \u2014 but when retrieval quality degrades, you must understand the underlying mechanics. The abstraction leaks at the seams.","connects_to":["conways-law","chestertons-fence","fallacies-distributed-computing"],"tags":["abstraction","frameworks","debugging"]},{"id":"fallacies-distributed-computing","name":"Fallacies of Dist. Computing","category":"failure","first_principle":"Eight assumptions developers wrongly make: network is reliable, latency is zero, bandwidth is infinite, network is secure, topology doesn't change, there is one admin, transport cost is zero, network is homogeneous.","derived_from":"Peter Deutsch; gaps between mental models and physical reality in networked systems","when_applies":"Any system that makes network calls \u2014 microservices, agents calling tools, RAG pipelines, multi-region deployments","when_breaks_down":"Single-process systems; embedded systems with no network dependency","ai_application":"AI agents that call external tools assume network reliability. An agentic loop that retries on failure without idempotency guards will corrupt state when the network is merely slow, not down.","connects_to":["cap-theorem","eventual-consistency","circuit-breaker"],"tags":["distributed-systems","networking","agents"]},{"id":"two-pizza-rule","name":"Two-Pizza Rule","category":"scale","first_principle":"If a team can't be fed by two pizzas, it's too big. Communication overhead scales as O(n\u00b2) with team size.","derived_from":"Jeff Bezos; combinatorial explosion of communication paths degrades coordination efficiency","when_applies":"Designing team structures, microservice ownership, agent crew sizes, context window allocation","when_breaks_down":"Tasks requiring rare expertise that can't be distributed; projects requiring tight coupling between many specialists","ai_application":"Multi-agent systems face the same n\u00b2 communication cost \u2014 a crew of 10 agents with shared state has 45 interaction paths. Design agent graphs with small, focused crews and explicit handoff contracts.","connects_to":["conways-law","amdhals-law","second-system-effect"],"tags":["team-design","multi-agent","scaling"]},{"id":"amdhals-law","name":"Amdahl's Law","category":"scale","first_principle":"The speedup from parallelizing a task is limited by its sequential fraction. If 20% must run serially, max speedup is 5x regardless of cores.","derived_from":"Gene Amdahl; fundamental limit on parallelism imposed by dependencies","when_applies":"Evaluating parallelism strategies, multi-agent fan-out, horizontal scaling, batch processing pipelines","when_breaks_down":"Embarrassingly parallel problems with no sequential dependencies (e.g., batch embedding generation)","ai_application":"A RAG pipeline with sequential steps (chunk \u2192 embed \u2192 retrieve \u2192 rerank \u2192 generate) has a hard latency floor even with infinite parallelism on individual steps. Identify and attack the sequential bottleneck first.","connects_to":["two-pizza-rule","littles-law","cap-theorem"],"tags":["performance","parallelism","scaling","latency"]},{"id":"littles-law","name":"Little's Law","category":"scale","first_principle":"L = \u03bbW. The average number of items in a system equals the arrival rate multiplied by the average time each item spends in the system.","derived_from":"John Little; a queuing theory result that holds for any stable system regardless of arrival/service distribution","when_applies":"Capacity planning, SLA design, sizing thread pools and connection pools, estimating agent concurrency needs","when_breaks_down":"Unstable systems where arrival rate exceeds service rate (the queue grows without bound)","ai_application":"If your Bedrock inference endpoint handles 10 req/s and average latency is 3s, you have 30 in-flight requests at steady state. Size your concurrency limits and token budgets accordingly.","connects_to":["amdhals-law","circuit-breaker","fallacies-distributed-computing"],"tags":["capacity","queuing","performance","sla"]},{"id":"second-system-effect","name":"Second System Effect","category":"cognitive","first_principle":"Engineers who succeed with a small first system tend to over-engineer the second, loading it with features deferred from the first.","derived_from":"Fred Brooks, The Mythical Man-Month; overconfidence after initial success breeds scope creep and complexity","when_applies":"Major rewrites, v2 architecture design, migrating from a POC to a production system","when_breaks_down":"Teams with strong discipline and explicit anti-scope-creep constraints; when the first system was genuinely too limited","ai_application":"POC AI architectures that work well tempt architects to add every deferred feature (memory, multi-tenancy, streaming, RLHF) in a single v2 sprint. Ship a walking skeleton first.","connects_to":["chestertons-fence","conways-law","two-pizza-rule"],"tags":["project-design","complexity","rewrites"]},{"id":"circuit-breaker","name":"Circuit Breaker","category":"failure","first_principle":"When a dependency fails repeatedly, stop calling it temporarily. Give it time to recover rather than amplifying failures with retries.","derived_from":"Michael Nygard, Release It!; electrical circuit breakers that prevent wiring fires by interrupting overload","when_applies":"Any system calling external dependencies \u2014 APIs, databases, AI inference endpoints, downstream services","when_breaks_down":"Idempotent read-only operations where retrying is harmless; internal function calls","ai_application":"Agentic tool-use loops that retry on failure can overwhelm a rate-limited Bedrock endpoint. A circuit breaker prevents cascading failure when the model is throttled.","connects_to":["fallacies-distributed-computing","littles-law","eventual-consistency"],"tags":["resilience","fault-tolerance","agents","inference"]},{"id":"eventual-consistency","name":"Eventual Consistency","category":"tradeoff","first_principle":"Given no new updates, all replicas will converge to the same value \u2014 eventually. The system trades strong consistency for availability and partition tolerance.","derived_from":"Werner Vogels / Dynamo paper; a deliberate design choice accepting temporary divergence for system-wide availability","when_applies":"Distributed caches, multi-region deployments, event-driven systems, AI memory stores updated asynchronously","when_breaks_down":"Financial transactions, inventory systems, or any domain where stale reads cause irreversible harm","ai_application":"Agent memory systems that write asynchronously are eventually consistent. An agent reading its own recent writes may get stale results \u2014 design read-after-write flows carefully.","connects_to":["cap-theorem","circuit-breaker","fallacies-distributed-computing"],"tags":["distributed-systems","consistency","memory","agents"]},{"id":"goodharts-law","name":"Goodhart's Law","category":"emergence","first_principle":"When a measure becomes a target, it ceases to be a good measure.","derived_from":"Charles Goodhart; optimizing for a proxy metric causes the proxy to decouple from the underlying goal","when_applies":"Designing evaluation frameworks, reward functions, KPIs, SLAs, or any system that optimizes toward a measurable proxy","when_breaks_down":"When the measure IS the goal (e.g., counting exact transactions processed)","ai_application":"Optimizing an AI agent for 'task completion rate' causes it to game easy tasks. RLHF models optimized on human preference ratings learn to produce confident-sounding wrong answers. Measure what you care about, not what's easy to measure.","connects_to":["survivorship-bias","distribution-shift","exploration-exploitation"],"tags":["evaluation","rlhf","metrics","alignment"]},{"id":"distribution-shift","name":"Distribution Shift","category":"ai-specific","first_principle":"A model trained on distribution P will degrade when deployed on distribution Q. The gap between training and production data is the primary source of model failure in production.","derived_from":"Statistical learning theory; generalization requires i.i.d. assumption that production routinely violates","when_applies":"Any ML/AI system in production; RAG systems as the knowledge base grows; embedding models as domain terminology evolves","when_breaks_down":"Truly static, closed-world problems where training and inference data are drawn from the same fixed distribution","ai_application":"A Bedrock Knowledge Base embedding model trained on general text degrades as your corpus adds specialized domain terminology. Monitor embedding quality over time, not just at launch.","connects_to":["goodharts-law","exploration-exploitation","leaky-abstractions"],"tags":["ml","embeddings","rag","monitoring","drift"]},{"id":"exploration-exploitation","name":"Exploration-Exploitation","category":"ai-specific","first_principle":"Any agent with limited time must balance exploiting known good actions against exploring potentially better unknown ones. You cannot fully do both.","derived_from":"Multi-armed bandit problem in reinforcement learning; generalizes to any resource-constrained search","when_applies":"AI agent action selection, retrieval strategy design (broad vs. precise search), hyperparameter tuning, feature development prioritization","when_breaks_down":"Single-shot decisions with no learning opportunity; fully enumerable action spaces","ai_application":"A RAG retrieval strategy that only exploits high-similarity chunks misses relevant context in lower-ranked results. Hybrid search (dense + sparse) is an exploration mechanism.","connects_to":["goodharts-law","distribution-shift","local-global-optima"],"tags":["rl","agents","rag","search","optimization"]},{"id":"local-global-optima","name":"Local vs. Global Optima","category":"cognitive","first_principle":"Local optimization can prevent reaching a global optimum. The best solution from where you stand is often not the best solution overall.","derived_from":"Optimization theory / gradient descent; systems that improve locally can become trapped in suboptimal equilibria","when_applies":"Architecture decisions under constraints, incremental refactoring, prompt engineering, hyperparameter search, organizational change","when_breaks_down":"Convex optimization problems where any local optimum is global; when the search space is small enough to enumerate","ai_application":"Incrementally tuning a RAG pipeline (chunk size, k, reranker threshold) can trap you in a local optimum. Sometimes you need to change the retrieval strategy wholesale \u2014 e.g., switching from semantic to hybrid search.","connects_to":["exploration-exploitation","chestertons-fence","second-system-effect"],"tags":["optimization","architecture","rag","refactoring"]},{"id":"survivorship-bias","name":"Survivorship Bias","category":"cognitive","first_principle":"We observe survivors, not failures. Conclusions drawn from visible successes systematically ignore the failed cases that would change the inference.","derived_from":"Abraham Wald / WWII aircraft armor study; selection effects distort the data we reason from","when_applies":"Post-mortems, benchmark comparisons, architecture pattern selection, evaluating AI outputs, model selection","when_breaks_down":"Controlled experiments with random assignment that explicitly sample from both success and failure","ai_application":"Benchmarks for LLM performance measure on curated test sets \u2014 the 'survivors' of data curation. Production failure modes are systematically absent. Always complement benchmarks with adversarial red-teaming.","connects_to":["goodharts-law","distribution-shift","chestertons-fence"],"tags":["evaluation","benchmarks","bias","testing"]},{"id":"two-generals-problem","name":"Two Generals Problem","category":"failure","first_principle":"It is impossible to achieve guaranteed consensus between two parties over an unreliable channel. Any acknowledgment can itself be lost.","derived_from":"Formal computer science result; proves that perfect coordination over unreliable networks is mathematically impossible","when_applies":"Distributed transactions, exactly-once delivery guarantees, agent handoff protocols, multi-step saga patterns","when_breaks_down":"Reliable synchronous channels (in-process calls); when at-least-once or at-most-once semantics are acceptable","ai_application":"When an AI agent hands off a task to a sub-agent over an async channel, you cannot guarantee exactly-once execution. Design for idempotency \u2014 safe to retry \u2014 rather than exactly-once.","connects_to":["cap-theorem","fallacies-distributed-computing","eventual-consistency"],"tags":["distributed-systems","agents","consensus","idempotency"]},{"id":"alignment-tax","name":"The Alignment Tax","category":"ai-specific","first_principle":"Safety and alignment constraints reduce raw capability. Every guardrail, refusal, or behavioral constraint is a deliberate capability tradeoff.","derived_from":"AI safety research; RLHF and constitutional AI introduce constraints that reduce performance on unconstrained benchmarks","when_applies":"Choosing models, designing system prompts, evaluating tradeoffs between helpfulness and safety, setting guardrails","when_breaks_down":"When alignment methods improve capability (e.g., chain-of-thought reasoning improves both safety and accuracy)","ai_application":"A Claude model with a restrictive system prompt will refuse some valid enterprise requests. Design your guardrails to be domain-specific, not maximally restrictive \u2014 over-constraining is a reliability failure.","connects_to":["goodharts-law","exploration-exploitation","leaky-abstractions"],"tags":["alignment","safety","prompting","model-selection"]},{"id":"feedback-loops","name":"Feedback Loops","category":"emergence","first_principle":"A system whose output feeds back as input creates amplifying (positive) or stabilizing (negative) loops. Positive loops accelerate; negative loops regulate.","derived_from":"Control theory / cybernetics; applies universally to any system with output-to-input coupling","when_applies":"Recommender systems, AI training pipelines, auto-scaling systems, event-driven architectures, model fine-tuning on production data","when_breaks_down":"Open-loop systems with no feedback path; when loop latency is so long the system is effectively open-loop","ai_application":"Fine-tuning a model on its own production outputs creates a positive feedback loop \u2014 errors compound. RAG systems that update their knowledge base from model-generated summaries face the same risk.","connects_to":["goodharts-law","distribution-shift","conways-law"],"tags":["systems-thinking","training","rag","fine-tuning","emergent-behavior"]},{"id":"zero-one-infinity","name":"Zero-One-Infinity","category":"tradeoff","first_principle":"Allow zero, one, or unlimited instances of something. Any other specific limit is arbitrary and will become a constraint you'll regret.","derived_from":"Willem van der Poel; arbitrary limits encode hidden assumptions that leak into future constraints","when_applies":"API design, multi-tenancy limits, prompt template slots, agent tool counts, context window management","when_breaks_down":"Hard physical limits (e.g., context windows); regulatory requirements imposing specific counts","ai_application":"If your RAG system supports 'up to 5 document types,' you will add a 6th. Design the pipeline for N document types from the start, with a registry pattern rather than hardcoded branches.","connects_to":["leaky-abstractions","second-system-effect","conways-law"],"tags":["api-design","scalability","architecture","rag"]},{"id":"pareto-principle","name":"Pareto Principle","category":"scale","first_principle":"Roughly 80% of effects come from 20% of causes. Input and output are not uniformly distributed \u2014 a small subset of inputs dominates outcomes.","derived_from":"Vilfredo Pareto's observation that 80% of Italian land was owned by 20% of people; generalized across economics, engineering, and natural systems","when_applies":"Prioritizing engineering effort, diagnosing performance bottlenecks, deciding which features to build, allocating testing coverage, triaging incidents","when_breaks_down":"Safety-critical systems where tail-case failures are catastrophic; regulated domains where all cases must be handled equally; adversarial environments where attackers target the neglected 80%","ai_application":"20% of query types account for 80% of your RAG pipeline's failures. Profile before optimizing \u2014 fixing the top failure bucket often collapses the error rate more than rewriting the whole pipeline.","connects_to":["amdhals-law","goodharts-law","bottleneck-theory","local-global-optima"],"tags":["prioritization","optimization","focus","efficiency"]},{"id":"bottleneck-theory","name":"Theory of Constraints","category":"scale","first_principle":"Every system has exactly one constraint that limits its throughput. Improving anything that is not the constraint improves nothing.","derived_from":"Eliyahu Goldratt, The Goal; the weakest link in a chain determines its total strength regardless of how strong the others are","when_applies":"Pipeline optimization, incident response, capacity planning, prioritizing engineering work, debugging latency in multi-step systems","when_breaks_down":"When the constraint shifts faster than you can address it; highly parallel systems with no shared bottleneck","ai_application":"In a RAG pipeline, if retrieval takes 800ms and generation takes 200ms, optimizing the LLM call gives you nothing. Identify the constraint first \u2014 it's almost always retrieval or chunking quality, not generation speed.","connects_to":["amdhals-law","pareto-principle","littles-law","feedback-loops"],"tags":["performance","optimization","pipeline","latency","rag"]},{"id":"separation-of-concerns","name":"Separation of Concerns","category":"tradeoff","first_principle":"A system is easier to reason about and change when each component has one clearly bounded responsibility, with minimal knowledge of other components.","derived_from":"Edsger Dijkstra; complexity grows when a single module must reason about multiple domains simultaneously","when_applies":"Service boundary design, prompt architecture, agent tool design, data pipeline structure, API contract definition","when_breaks_down":"Performance-critical paths where crossing boundaries is too expensive; very small systems where the overhead of separation exceeds the benefit","ai_application":"A system prompt that handles persona, output format, safety rules, domain knowledge, and tool instructions in one block is hard to debug and update. Separate concerns: use structured sections or layered prompts. Each agent in a crew should own exactly one concern.","connects_to":["conways-law","leaky-abstractions","single-responsibility","zero-one-infinity"],"tags":["design","prompting","agents","modularity","api-design"]},{"id":"single-responsibility","name":"Single Responsibility","category":"tradeoff","first_principle":"A module should have one and only one reason to change. Coupling multiple responsibilities means a change to either forces changes to both.","derived_from":"Robert C. Martin; a special case of separation of concerns focused on the axis of change rather than cognitive load","when_applies":"Designing functions, microservices, Lambda handlers, agents, tool definitions, data models","when_breaks_down":"Extremely simple scripts where splitting creates more overhead than it saves; tightly coupled domain operations that genuinely change together","ai_application":"An agent that both decides what to do AND executes it AND logs it AND validates results is hard to test, debug, or swap out. Design narrow agents: one decides, another executes, another validates.","connects_to":["separation-of-concerns","conways-law","leaky-abstractions","two-pizza-rule"],"tags":["design","agents","microservices","testability"]},{"id":"postel-law","name":"Postel's Law","category":"tradeoff","first_principle":"Be conservative in what you send, liberal in what you accept. Robust systems tolerate imperfect inputs without breaking, but produce well-formed outputs.","derived_from":"Jon Postel, RFC 793 (TCP); designed to keep the internet working despite heterogeneous, imperfect implementations","when_applies":"API design, message schema evolution, inter-service contracts, parsing user input, designing agent tool interfaces","when_breaks_down":"Security-sensitive inputs where accepting anything enables injection attacks; when liberal acceptance masks bugs in callers and breeds long-term protocol entropy","ai_application":"LLM outputs are liberal producers \u2014 they rarely produce perfectly structured JSON. Your parsing layer must be robust to minor format deviations. But your agent's tool outputs should be strictly typed so downstream agents can rely on them.","connects_to":["separation-of-concerns","leaky-abstractions","zero-one-infinity","fallacies-distributed-computing"],"tags":["api-design","parsing","agents","robustness","schema"]},{"id":"idempotency","name":"Idempotency","category":"failure","first_principle":"An operation that produces the same result whether applied once or many times is safe to retry. Without idempotency, retries cause duplication or corruption.","derived_from":"Mathematics (idempotent functions); foundational to reliable distributed systems \u2014 retries are inevitable, so operations must be safe to repeat","when_applies":"Any operation that can be retried \u2014 API calls, event handlers, database writes, agent tool calls, payment processing, message consumers","when_breaks_down":"Pure reads (already safe); true one-time events where idempotency is impossible and exactly-once delivery must be guaranteed at the infrastructure level","ai_application":"Agentic tool calls will be retried \u2014 by the agent, by the orchestrator, or by infrastructure. A non-idempotent tool call (e.g., 'send email') will send duplicate emails. Every tool an agent can call should either be idempotent or carry an explicit deduplication key.","connects_to":["two-generals-problem","circuit-breaker","fallacies-distributed-computing","event-driven-architecture"],"tags":["resilience","agents","distributed-systems","retries","tools"]},{"id":"event-driven-architecture","name":"Event-Driven Architecture","category":"tradeoff","first_principle":"Components communicate by emitting and reacting to events rather than calling each other directly. The producer doesn't know who consumes; the consumer doesn't know who produced.","derived_from":"Observer pattern / reactive systems manifesto; decoupling via an event bus reduces direct dependencies and enables async processing","when_applies":"Systems requiring loose coupling between services, async processing, fan-out to multiple consumers, audit trails, temporal decoupling","when_breaks_down":"When you need synchronous request-response semantics; when event ordering guarantees are required but hard to enforce; when debugging event chains becomes opaque","ai_application":"Agentic pipelines map naturally to event-driven patterns \u2014 an agent emitting a 'document-processed' event decouples ingestion from indexing from notification. But debugging a hallucination in a 6-event chain is significantly harder than a synchronous call.","connects_to":["idempotency","eventual-consistency","feedback-loops","separation-of-concerns"],"tags":["architecture","async","messaging","decoupling","agents"]},{"id":"observability-triangle","name":"Observability Triangle","category":"failure","first_principle":"You cannot debug what you cannot observe. Logs tell you what happened. Metrics tell you how much. Traces tell you where. All three are required; any one alone is insufficient.","derived_from":"Distributed systems practice (Charity Majors et al.); the 3 pillars of observability \u2014 logs, metrics, traces \u2014 each answer different questions about system behavior","when_applies":"Any production system; especially multi-step pipelines, microservices, agentic workflows, and AI inference chains where failure modes are emergent","when_breaks_down":"Simple scripts or single-process systems where stdout is sufficient; extremely cost-sensitive deployments where full observability is prohibitive","ai_application":"An agentic pipeline without traces is a black box. When Claude returns a wrong answer, you need to know which tool call failed, which retrieved chunk was misleading, and which prompt template was active. Instrument every hop, not just the final output.","connects_to":["feedback-loops","distribution-shift","circuit-breaker","goodharts-law"],"tags":["observability","debugging","monitoring","agents","tracing"]},{"id":"defence-in-depth","name":"Defence in Depth","category":"failure","first_principle":"No single security control is sufficient. Layer multiple independent controls so that the failure of any one does not compromise the system.","derived_from":"Military strategy (castle walls + moat + keep); applied to information security \u2014 each layer catches what the previous missed","when_applies":"Security architecture, prompt injection defence, AI guardrail design, IAM policy design, multi-tenant data isolation","when_breaks_down":"When layers are not truly independent (a single exploit breaks all layers); when the cost of layering exceeds the risk it mitigates","ai_application":"A single system prompt guardrail is insufficient defence against prompt injection. Layer: input validation \u2192 system prompt \u2192 output filtering \u2192 downstream action validation. Each layer catches a different attack vector.","connects_to":["zero-trust","least-privilege","chestertons-fence","alignment-tax"],"tags":["security","prompting","guardrails","multi-tenancy","injection"]},{"id":"least-privilege","name":"Least Privilege","category":"failure","first_principle":"Every component should have access only to the resources it needs to perform its function, and no more. Excess privilege is an attack surface.","derived_from":"Jerome Saltzer & Michael Schroeder, 1975; minimizing access scope minimizes blast radius when any component is compromised","when_applies":"IAM roles, agent tool permissions, API scopes, database access, service accounts, multi-tenant data access","when_breaks_down":"Administrative tasks that genuinely require broad access; emergency break-glass scenarios; bootstrapping a system before least-privilege boundaries are established","ai_application":"An AI agent with access to every tool in your catalog can cause catastrophic harm when it hallucinates a tool call. Give each agent a minimal, task-specific toolset. A document summariser should not have write access to production databases.","connects_to":["defence-in-depth","zero-trust","separation-of-concerns","idempotency"],"tags":["security","iam","agents","blast-radius","permissions"]},{"id":"zero-trust","name":"Zero Trust","category":"failure","first_principle":"Never trust, always verify. No component should be trusted by virtue of its network location or identity alone \u2014 every request must be authenticated and authorized.","derived_from":"John Kindervag, 2010; a response to the failure of perimeter-based security models where internal traffic was implicitly trusted","when_applies":"Multi-tenant systems, microservice authentication, agent-to-agent calls, API gateway design, any system where lateral movement is a threat","when_breaks_down":"Fully isolated single-tenant systems with no external attack surface; when the cost of verification exceeds the risk of implicit trust","ai_application":"In a multi-agent system, an agent receiving a tool call result should not assume it came from a trusted orchestrator \u2014 prompt injection can hijack the orchestrator. Verify caller identity and validate inputs at every boundary.","connects_to":["least-privilege","defence-in-depth","idempotency","fallacies-distributed-computing"],"tags":["security","authentication","multi-tenant","agents","iam"]},{"id":"blast-radius","name":"Blast Radius","category":"failure","first_principle":"When something fails, limit how much of the system it can damage. Design explicit containment boundaries so a failure in one area cannot cascade to everything.","derived_from":"Military engineering; the zone of destruction from an explosion is bounded by distance and barriers \u2014 applied to systems design as fault isolation","when_applies":"Service isolation, cell-based architecture, multi-tenant isolation, agent sandboxing, database per service, canary deployments","when_breaks_down":"Systems so tightly coupled that isolation is architecturally impossible; when the cost of isolation exceeds the risk of cascade","ai_application":"A shared Bedrock Knowledge Base across all tenants means one tenant's bad document poisons everyone's retrieval. Per-tenant isolation (separate indices or strict metadata filtering) contains the blast radius.","connects_to":["least-privilege","defence-in-depth","circuit-breaker","cell-based-architecture"],"tags":["resilience","fault-isolation","multi-tenant","security","agents"]},{"id":"cell-based-architecture","name":"Cell-Based Architecture","category":"scale","first_principle":"Partition a system into independent, identically structured cells. Each cell serves a subset of traffic. A failure in one cell cannot affect others.","derived_from":"Amazon/Netflix engineering; sharding by natural unit (tenant, region, user cohort) creates blast radius boundaries at infrastructure level","when_applies":"Multi-tenant SaaS, regional deployments, high-availability architectures, systems where one tenant's load must not affect another's","when_breaks_down":"Small-scale systems where cell overhead is unjustified; workloads with no natural sharding key","ai_application":"A per-tenant cell in a multi-tenant RAG system gives each tenant isolated S3 buckets, Knowledge Base indices, and inference quotas. One tenant's indexing storm cannot degrade another's query latency.","connects_to":["blast-radius","least-privilege","zero-one-infinity","amdhals-law"],"tags":["multi-tenant","saas","isolation","scaling","aws"]},{"id":"caching-hierarchy","name":"Caching Hierarchy","category":"tradeoff","first_principle":"Every cache trades consistency for speed. The closer the cache is to the consumer, the faster it is and the more stale it can become. You must explicitly decide how much staleness you can tolerate.","derived_from":"CPU cache hierarchy (L1/L2/L3/RAM/disk); the memory hierarchy is the canonical example of trading distance for freshness","when_applies":"API response caching, embedding caches, KV store design, CDN strategy, database query caches, prompt/response caching","when_breaks_down":"Data that must always be fresh (financial balances, inventory); caches that become so large they are effectively the source of truth","ai_application":"Caching embeddings for frequently queried documents dramatically reduces Bedrock Titan API costs. But if a document is updated and the cache isn't invalidated, your RAG system returns answers grounded in stale content \u2014 silently.","connects_to":["eventual-consistency","cap-theorem","distribution-shift","observability-triangle"],"tags":["performance","cost","consistency","rag","embeddings"]},{"id":"schema-on-read-vs-write","name":"Schema-on-Read vs. Write","category":"tradeoff","first_principle":"You can enforce structure when data is written (schema-on-write) or when it is read (schema-on-read). Write enforcement provides consistency; read enforcement provides flexibility.","derived_from":"Data engineering / Hadoop era; data lakes vs. data warehouses; the tension between ingestion speed and query reliability","when_applies":"Data pipeline design, document store choice, event schema evolution, AI knowledge base ingestion, multi-source data integration","when_breaks_down":"Neither extreme is always right; most production systems are hybrid, enforcing a minimal write schema while tolerating optional fields at read time","ai_application":"Ingesting heterogeneous documents into a RAG knowledge base is a schema-on-read problem \u2014 you don't know what structure the documents have at ingest time. But your output schema (what the agent returns to callers) should be strictly schema-on-write.","connects_to":["postel-law","separation-of-concerns","event-driven-architecture","leaky-abstractions"],"tags":["data","schema","rag","ingestion","pipeline"]},{"id":"law-of-demeter","name":"Law of Demeter","category":"tradeoff","first_principle":"A component should only talk to its immediate collaborators, not to collaborators of collaborators. Don't reach through objects to get to what you need.","derived_from":"Ian Holland, 1987; 'only talk to your friends' \u2014 transitive dependencies create invisible coupling and propagate changes across unrelated modules","when_applies":"API design, service mesh call patterns, agent orchestration, data model design, tool interface design","when_breaks_down":"Facade patterns that deliberately aggregate deep access; data transfer objects explicitly designed to carry data across layers","ai_application":"An orchestrator agent that directly manipulates a sub-agent's internal memory store is violating Demeter. If the memory store changes, the orchestrator breaks. Route all access through the sub-agent's declared interface.","connects_to":["separation-of-concerns","single-responsibility","leaky-abstractions","conways-law"],"tags":["design","coupling","agents","api-design"]},{"id":"cynefin-framework","name":"Cynefin Framework","category":"cognitive","first_principle":"Problems exist in four domains: Simple (apply best practice), Complicated (expert analysis), Complex (cause/effect only visible in retrospect \u2014 probe then act), Chaotic (act first, stabilize). Applying the wrong response to the domain causes harm.","derived_from":"Dave Snowden, IBM; a sensemaking framework for deciding how to respond based on the nature of a problem's causality","when_applies":"Architecture decision-making, incident response, deciding when to run experiments vs. apply known patterns, evaluating AI system behavior","when_breaks_down":"When the domain is misidentified \u2014 the most common failure; in fast-moving situations where there's no time for domain assessment","ai_application":"LLM behavior in production is Complex, not Complicated. You cannot analyze your way to the right system prompt \u2014 you must probe (run evals), observe the response, then adapt. Applying 'best practice' prompting to a novel domain without probing first is a category error.","connects_to":["exploration-exploitation","local-global-optima","survivorship-bias","goodharts-law"],"tags":["decision-making","complexity","sensemaking","prompting","architecture"]},{"id":"two-way-door","name":"Two-Way Door Decisions","category":"cognitive","first_principle":"Distinguish reversible decisions (two-way doors \u2014 decide fast, course-correct later) from irreversible ones (one-way doors \u2014 decide slowly, with full information). Treating all decisions as one-way doors is the biggest cause of organisational slowness.","derived_from":"Jeff Bezos, Amazon shareholder letters; the asymmetry of reversibility should determine how much process you apply to a decision","when_applies":"Architecture decisions, technology choices, API contracts, data model design, team structure changes","when_breaks_down":"When a decision that appears reversible creates hidden path dependencies that make reversal effectively impossible","ai_application":"Choosing which embedding model to use for a Bedrock Knowledge Base is a one-way door \u2014 switching means re-embedding your entire corpus. Choosing a chunk size is a two-way door. Apply disproportionate rigor to the former.","connects_to":["chestertons-fence","cynefin-framework","local-global-optima","second-system-effect"],"tags":["decision-making","architecture","risk","embeddings","rag"]},{"id":"cognitive-load-theory","name":"Cognitive Load Theory","category":"cognitive","first_principle":"Human working memory is limited to 4\u00b11 chunks simultaneously. System complexity that exceeds this limit causes errors, not just discomfort. Complexity is a tax paid in mistakes.","derived_from":"John Sweller, 1988; cognitive psychology applied to instructional design, and now widely applied to software design and API usability","when_applies":"API design, system prompt design, onboarding documentation, code review, architecture diagram design, multi-step workflow design","when_breaks_down":"Expert users with extensive domain models who have effectively cached complexity into long-term memory; automated systems with no human in the loop","ai_application":"A system prompt with 20 numbered rules exceeds working memory for both the LLM (attention dilution) and the human maintaining it. Collapse rules into principles; use structured sections to chunk complexity. The model can't 'hold' every rule simultaneously any more than a human can.","connects_to":["separation-of-concerns","two-pizza-rule","cynefin-framework","law-of-demeter"],"tags":["prompting","ux","api-design","documentation","complexity"]},{"id":"normalisation-of-deviance","name":"Normalisation of Deviance","category":"emergence","first_principle":"When a system repeatedly violates safety norms without immediate failure, those violations become accepted as normal. The absence of disaster is mistaken for evidence of safety.","derived_from":"Diane Vaughan's analysis of the Space Shuttle Challenger disaster; small acceptable deviations accumulate until catastrophic failure","when_applies":"Production systems with accumulating tech debt, security exceptions that persist, AI systems with known but tolerated failure modes, manual override processes","when_breaks_down":"Systems with rapid, clear feedback loops where every deviation is immediately visible; highly regulated environments with strict enforcement","ai_application":"A RAG system that 'usually gets it right' creates normalised deviance around hallucinations. Teams stop filing bugs for 'minor' hallucinations. Over time, the acceptable error rate drifts upward and no one knows the true production failure rate.","connects_to":["feedback-loops","observability-triangle","goodharts-law","survivorship-bias"],"tags":["risk","safety","monitoring","ai-safety","culture"]},{"id":"premature-optimisation","name":"Premature Optimisation","category":"cognitive","first_principle":"Optimising before you know where the bottleneck is wastes effort and adds complexity. Make it correct first, then measure, then optimise the measured bottleneck.","derived_from":"Donald Knuth: 'premature optimisation is the root of all evil'; optimisation without measurement targets the wrong thing 80% of the time","when_applies":"Any engineering work \u2014 code, architecture, prompts, pipelines; especially early in a project before real usage patterns are known","when_breaks_down":"Known, fixed bottlenecks that are predictable from first principles; systems where correctness and performance cannot be separated","ai_application":"Spending two weeks optimising your embedding chunk size before you have 100 real user queries is premature optimisation. Instrument first, get real query patterns, then tune. Most RAG performance problems are in retrieval quality, not chunk size arithmetic.","connects_to":["bottleneck-theory","pareto-principle","observability-triangle","cynefin-framework"],"tags":["performance","engineering-practice","rag","measurement"]},{"id":"strangler-fig-pattern","name":"Strangler Fig Pattern","category":"tradeoff","first_principle":"Incrementally replace a legacy system by routing new functionality through a new system alongside the old one, gradually shifting traffic until the old system can be retired.","derived_from":"Martin Fowler; named after the strangler fig tree that grows around a host tree \u2014 a metaphor for incremental, safe migration that avoids a risky big-bang cutover","when_applies":"Migrating monoliths to microservices, replacing legacy integrations, introducing AI into existing workflows, upgrading data pipelines without downtime","when_breaks_down":"Systems so tightly coupled that a seam cannot be introduced; when the old and new systems cannot run in parallel without data consistency problems","ai_application":"When introducing AI into an existing workflow (e.g., replacing a rules-based document classifier with an LLM), run both systems in parallel first. Shadow the AI output against the rules engine, measure divergence, build confidence, then cut over incrementally.","connects_to":["two-way-door","chestertons-fence","second-system-effect","normalisation-of-deviance"],"tags":["migration","refactoring","ai-adoption","risk","architecture"]},{"id":"context-window-as-working-memory","name":"Context Window = Working Memory","category":"ai-specific","first_principle":"An LLM's context window is its only working memory. Everything the model knows about the current task must fit in that window. What isn't in the context doesn't exist to the model.","derived_from":"Transformer architecture; attention is computed over the full context \u2014 the model has no persistent state between calls beyond what is explicitly provided","when_applies":"Prompt engineering, multi-turn agent design, RAG architecture, conversation summarisation, long-document processing, agentic loop design","when_breaks_down":"Models with explicit external memory tools; architectures where persistence is handled outside the model (e.g., Bedrock Agent Core Memory)","ai_application":"An agentic loop that accumulates tool results in the context window will eventually overflow. Design explicit summarisation and eviction strategies \u2014 treat the context window like a finite buffer, not infinite scratch space.","connects_to":["cognitive-load-theory","exploration-exploitation","separation-of-concerns","caching-hierarchy"],"tags":["llm","prompting","agents","memory","context"]},{"id":"ground-truth-gap","name":"Ground Truth Gap","category":"ai-specific","first_principle":"The quality of an AI system is bounded by the quality of its evaluation. Without reliable ground truth, you cannot distinguish a system that is improving from one that is getting better at fooling your metrics.","derived_from":"Machine learning practice; the hardest part of building AI systems is not the model but the evaluation \u2014 labelled data is the scarcest resource","when_applies":"Building evaluation harnesses for LLMs, designing RAG quality metrics, assessing agent correctness, fine-tuning data curation, red-teaming","when_breaks_down":"Well-defined closed-world tasks where ground truth is unambiguous (e.g., code execution, mathematical proofs)","ai_application":"Most RAG pipelines are evaluated by asking the LLM if its own answer is correct \u2014 an LLM grading its own work. This measures fluency, not factual correctness. Invest in human-labelled golden datasets for your domain before trusting automated metrics.","connects_to":["goodharts-law","survivorship-bias","distribution-shift","observability-triangle"],"tags":["evaluation","rag","testing","metrics","quality"]},{"id":"temperature-creativity-tradeoff","name":"Temperature & Creativity","category":"ai-specific","first_principle":"Higher sampling temperature increases output diversity at the cost of reliability. Lower temperature increases consistency at the cost of creativity. There is no free lunch.","derived_from":"Softmax temperature in language model sampling; scaling logits changes the probability distribution over tokens from peaked (deterministic) to flat (random)","when_applies":"Choosing inference parameters, designing agent personas, building classification vs. generation systems, A/B testing prompt strategies","when_breaks_down":"Tasks where determinism matters absolutely (use temperature=0); tasks where diversity is the sole goal and consistency is irrelevant","ai_application":"A RAG system answering factual questions should use low temperature (0\u20130.3). An agent brainstorming architecture alternatives should use higher temperature (0.7\u20131.0). Using the same temperature for both is a common misconfiguration.","connects_to":["exploration-exploitation","alignment-tax","ground-truth-gap","context-window-as-working-memory"],"tags":["inference","prompting","llm","configuration","agents"]},{"id":"toil-vs-investment","name":"Toil vs. Investment","category":"cognitive","first_principle":"Toil is manual, repetitive, automatable work that scales linearly with system size and produces no lasting value. Investment is work that reduces future toil. A system generating more toil than investment is compounding technical debt.","derived_from":"Google SRE book; the 'toil budget' concept \u2014 SREs should spend no more than 50% of time on toil, or the system is unmanageable at scale","when_applies":"Evaluating automation priorities, runbook design, deciding when to build tooling vs. do things manually, sizing on-call burden","when_breaks_down":"One-off tasks that will never recur; situations where the cost of automation exceeds the lifetime toil it would eliminate","ai_application":"Manually reviewing every AI-generated output before it reaches users is toil. It scales with request volume, not engineering headcount. Build automated evaluation pipelines early \u2014 they are investment that reduces toil as the system scales.","connects_to":["pareto-principle","bottleneck-theory","observability-triangle","normalisation-of-deviance"],"tags":["sre","automation","engineering-practice","scaling","evaluation"]},{"id":"reversibility-entropy","name":"Reversibility & Entropy","category":"emergence","first_principle":"Systems naturally drift toward disorder over time. Without active investment in order, complexity accumulates, documentation goes stale, and technical debt compounds. Maintenance is not optional \u2014 it is the price of operation.","derived_from":"Second law of thermodynamics applied to software; systems entropy was formalised by Manny Lehman's laws of software evolution","when_applies":"Long-lived systems, legacy migration planning, documentation strategy, dependency management, prompt and knowledge base maintenance","when_breaks_down":"Short-lived systems designed to be thrown away; systems with extremely stable domains that genuinely don't change","ai_application":"A Bedrock Knowledge Base that isn't actively maintained drifts out of sync with reality. Documents become stale, embeddings represent old terminology, and the system confidently answers questions with outdated facts. Schedule entropy work \u2014 it's not optional.","connects_to":["chestertons-fence","normalisation-of-deviance","feedback-loops","distribution-shift"],"tags":["maintenance","technical-debt","rag","knowledge-base","lifecycle"]},{"id":"map-territory-distinction","name":"Map-Territory Distinction","category":"cognitive","first_principle":"The map is not the territory. Every model, diagram, schema, or abstraction is a simplified representation of reality, not reality itself. Acting as if the map is the territory causes systematic errors.","derived_from":"Alfred Korzybski, 1931; the map analogy highlights that all mental models are lossy compressions of an underlying reality","when_applies":"Architecture diagrams, data models, SLA definitions, benchmark results, AI system evaluations, capacity models","when_breaks_down":"Formal systems (mathematics, logic) where the model IS the territory by definition","ai_application":"An LLM's 'knowledge' is a map of the world at training time, not the world itself. When you ask Claude about a live system, it answers from its map, not from your reality. RAG is the mechanism for injecting current territory into the model's map.","connects_to":["distribution-shift","ground-truth-gap","leaky-abstractions","cynefin-framework"],"tags":["mental-models","abstraction","llm","rag","epistemology"]},{"id":"occams-razor","name":"Occam's Razor","category":"cognitive","first_principle":"Among competing explanations or solutions of equal explanatory power, prefer the simplest. Complexity should not be added without a demonstrated need.","derived_from":"William of Ockham, 14th century; the principle that entities should not be multiplied beyond necessity \u2014 now foundational to scientific inference and engineering design","when_applies":"Architecture decisions, incident diagnosis, model selection, prompt design, explaining AI outputs, choosing between two solutions of similar efficacy","when_breaks_down":"Problems with genuine irreducible complexity; when the simple explanation is demonstrably wrong and only a complex one fits the evidence","ai_application":"When a RAG system returns a wrong answer, the simplest explanation (wrong chunk retrieved) is usually correct. Don't hypothesize model hallucination, embedding model failure, and chunking bugs simultaneously \u2014 test the simplest cause first.","connects_to":["cynefin-framework","premature-optimisation","second-system-effect","map-territory-distinction"],"tags":["design","debugging","decision-making","simplicity","architecture"]}];

const CATEGORY_META = {
  tradeoff:      { label: "Tradeoff",    color: "#E8A838", glyph: "⇌" },
  failure:       { label: "Failure",     color: "#E05252", glyph: "✕" },
  scale:         { label: "Scale",       color: "#4EAEFF", glyph: "↑" },
  emergence:     { label: "Emergence",   color: "#7EC87E", glyph: "◎" },
  cognitive:     { label: "Cognitive",   color: "#B57BFF", glyph: "⊙" },
  "ai-specific": { label: "AI",          color: "#FF7EC8", glyph: "⚡" },
};

function useForceLayout(models, width, height) {
  const [positions, setPositions] = useState({});
  const frameRef = useRef(null);
  const stateRef = useRef({});
  useEffect(() => {
    if (!models.length || !width || !height) return;
    cancelAnimationFrame(frameRef.current);
    const pos = {};
    models.forEach((m, i) => {
      const a = (i / models.length) * 2 * Math.PI;
      const r = Math.min(width, height) * 0.32;
      pos[m.id] = { x: width/2 + r*Math.cos(a) + (Math.random()-.5)*80, y: height/2 + r*Math.sin(a) + (Math.random()-.5)*80, vx:0, vy:0 };
    });
    stateRef.current = pos;
    const edges = [];
    const idSet = new Set(models.map(m => m.id));
    models.forEach(m => (m.connects_to||[]).forEach(t => { if(idSet.has(t)) edges.push([m.id,t]); }));
    let iter = 0;
    const tick = () => {
      if (iter++ > 400) return;
      const cur = stateRef.current;
      const nx = {};
      models.forEach(m => { nx[m.id] = { ...cur[m.id] }; });
      for (let i=0;i<models.length;i++) for(let j=i+1;j<models.length;j++){
        const a=cur[models[i].id],b=cur[models[j].id];
        const dx=a.x-b.x,dy=a.y-b.y,d=Math.sqrt(dx*dx+dy*dy)||1;
        const f=7000/(d*d); const fx=dx/d*f,fy=dy/d*f;
        nx[models[i].id].vx+=fx; nx[models[i].id].vy+=fy;
        nx[models[j].id].vx-=fx; nx[models[j].id].vy-=fy;
      }
      edges.forEach(([ai,bi])=>{ const a=cur[ai],b=cur[bi]; if(!a||!b) return;
        const dx=b.x-a.x,dy=b.y-a.y,d=Math.sqrt(dx*dx+dy*dy)||1;
        const f=(d-160)*0.04; const fx=dx/d*f,fy=dy/d*f;
        nx[ai].vx+=fx;nx[ai].vy+=fy; nx[bi].vx-=fx;nx[bi].vy-=fy;
      });
      models.forEach(m=>{ nx[m.id].vx+=(width/2-cur[m.id].x)*0.006; nx[m.id].vy+=(height/2-cur[m.id].y)*0.006; });
      const pad=80;
      models.forEach(m=>{ const n=nx[m.id]; n.vx*=0.68;n.vy*=0.68;
        n.x=Math.max(pad,Math.min(width-pad,cur[m.id].x+n.vx));
        n.y=Math.max(pad,Math.min(height-pad,cur[m.id].y+n.vy));
      });
      stateRef.current = nx;
      setPositions({...nx});
      frameRef.current = requestAnimationFrame(tick);
    };
    frameRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameRef.current);
  }, [models.map(m=>m.id).join(","), width, height]);
  return positions;
}

function SettingsModal({ onClose, onLoad }) {
  const [url, setUrl] = useState("https://raw.githubusercontent.com/YOUR_USERNAME/mental-models/main/models.json");
  const [status, setStatus] = useState(null);
  const handleLoad = async () => {
    setStatus("loading");
    try {
      const res = await fetch(url);
      if(!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      if(!data.models?.length) throw new Error("No models array found");
      onLoad(data.models); setStatus("ok"); setTimeout(onClose, 700);
    } catch(e) { setStatus("error: "+e.message); }
  };
  return (
    <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(4,6,14,0.92)",backdropFilter:"blur(8px)",display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={onClose}>
      <div style={{background:"#0B0D1A",border:"1px solid #1E2640",borderTop:"3px solid #4EAEFF",borderRadius:2,padding:"28px 32px",maxWidth:520,width:"100%",fontFamily:"'DM Mono','Fira Mono',monospace"}} onClick={e=>e.stopPropagation()}>
        <h3 style={{margin:"0 0 6px",color:"#F0F4FF",fontSize:15,fontWeight:600}}>Load from GitHub</h3>
        <p style={{margin:"0 0 20px",color:"#4A5670",fontSize:12,lineHeight:1.7}}>Paste your <code style={{color:"#4EAEFF"}}>raw.githubusercontent.com</code> URL to <code style={{color:"#4EAEFF"}}>models.json</code>. Push new models, then reload here.</p>
        <input value={url} onChange={e=>setUrl(e.target.value)} style={{width:"100%",background:"#070910",border:"1px solid #1E2640",color:"#B0BAD0",padding:"9px 12px",borderRadius:2,fontFamily:"inherit",fontSize:11,marginBottom:12,boxSizing:"border-box",outline:"none"}} />
        <div style={{display:"flex",gap:10,alignItems:"center"}}>
          <button onClick={handleLoad} style={{background:"#4EAEFF18",border:"1px solid #4EAEFF55",color:"#4EAEFF",padding:"7px 18px",borderRadius:2,fontFamily:"inherit",fontSize:12,cursor:"pointer"}}>{status==="loading"?"Loading…":"Fetch Models"}</button>
          <button onClick={onClose} style={{background:"none",border:"1px solid #1E2640",color:"#4A5670",padding:"7px 18px",borderRadius:2,fontFamily:"inherit",fontSize:12,cursor:"pointer"}}>Cancel</button>
          {status && status!=="loading" && <span style={{fontSize:12,color:status==="ok"?"#7EC87E":"#E05252"}}>{status==="ok"?"✓ Loaded":status}</span>}
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [models, setModels] = useState(SEED_MODELS);
  const [selected, setSelected] = useState(null);
  const [filter, setFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [showSettings, setShowSettings] = useState(false);
  const containerRef = useRef(null);
  const [dims, setDims] = useState({ w: 900, h: 600 });

  useEffect(() => {
    const ro = new ResizeObserver(entries => {
      const r = entries[0].contentRect;
      setDims({ w: r.width, h: r.height });
    });
    if (containerRef.current) ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  const displayed = useMemo(() => {
    let list = filter === "all" ? models : models.filter(m => m.category === filter);
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(m => m.name.toLowerCase().includes(q) || (m.tags||[]).some(t=>t.includes(q)) || m.first_principle.toLowerCase().includes(q));
    }
    return list;
  }, [models, filter, search]);

  const positions = useForceLayout(displayed, dims.w, dims.h);

  const edges = useMemo(() => {
    const result = [], idSet = new Set(displayed.map(m=>m.id));
    displayed.forEach(m => (m.connects_to||[]).forEach(t => { if(idSet.has(t) && m.id < t) result.push([m.id,t]); }));
    return result;
  }, [displayed]);

  const connectedIds = useMemo(() => {
    if (!selected) return new Set();
    const s = new Set([selected.id]);
    (selected.connects_to||[]).forEach(id => s.add(id));
    displayed.forEach(m => { if((m.connects_to||[]).includes(selected.id)) s.add(m.id); });
    return s;
  }, [selected, displayed]);

  const meta = selected ? (CATEGORY_META[selected.category]||{}) : {};

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#07090F",color:"#F0F4FF",fontFamily:"'DM Mono','Fira Mono',monospace",overflow:"hidden"}}>
      {/* Topbar */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 20px",height:50,borderBottom:"1px solid #141828",background:"#090B15",flexShrink:0,gap:12}}>
        <div style={{display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:"#4EAEFF",boxShadow:"0 0 10px #4EAEFF88"}}/>
            <span style={{fontSize:12,fontWeight:700,letterSpacing:"0.08em",color:"#D8E4FF"}}>MENTAL MODELS</span>
            <span style={{color:"#2A3450",fontSize:10}}>architecture + AI</span>
          </div>
          <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
            {[["all","All","#4EAEFF"],...Object.entries(CATEGORY_META).map(([k,v])=>[k,v.glyph+" "+v.label,v.color])].map(([key,label,color])=>(
              <button key={key} onClick={()=>setFilter(key)} style={{background:filter===key?color+"1A":"none",border:`1px solid ${filter===key?color+"66":"#141828"}`,color:filter===key?color:"#3A4460",padding:"2px 9px",borderRadius:2,fontSize:10,cursor:"pointer",fontFamily:"inherit",transition:"all .15s"}}>{label}</button>
            ))}
          </div>
        </div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="search…" style={{background:"#0B0D18",border:"1px solid #141828",color:"#B0BAD0",padding:"4px 10px",borderRadius:2,fontFamily:"inherit",fontSize:10,width:150,outline:"none"}} />
          <button onClick={()=>setShowSettings(true)} style={{background:"none",border:"1px solid #1E2640",color:"#3A4460",padding:"4px 10px",borderRadius:2,fontSize:10,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>⊕ GitHub</button>
        </div>
      </div>

      {/* Body */}
      <div style={{display:"flex",flex:1,overflow:"hidden",position:"relative"}}>
        <div ref={containerRef} style={{flex:1,position:"relative"}}>
          <svg width="100%" height="100%" style={{display:"block"}}>
            {edges.map(([ai,bi])=>{
              const a=positions[ai],b=positions[bi]; if(!a||!b) return null;
              const hi = selected && connectedIds.has(ai) && connectedIds.has(bi);
              return <line key={`${ai}-${bi}`} x1={a.x} y1={a.y} x2={b.x} y2={b.y} stroke={hi?"#4EAEFF":"#1C2238"} strokeWidth={hi?1.5:.7} opacity={hi?.75:.5} style={{transition:"all .2s"}} />;
            })}
            {displayed.map(m=>{
              const pos=positions[m.id]; if(!pos) return null;
              const cm=CATEGORY_META[m.category]||{};
              const isSel=selected?.id===m.id;
              const isDim=selected && !connectedIds.has(m.id);
              const sz=isSel?13:9;
              return (
                <g key={m.id} transform={`translate(${pos.x},${pos.y})`} style={{cursor:"pointer",opacity:isDim?.15:1,transition:"opacity .2s"}} onClick={()=>setSelected(selected?.id===m.id?null:m)}>
                  {isSel && <circle r={22} fill={cm.color+"12"}/>}
                  <circle r={sz} fill={isSel?cm.color:cm.color+"2A"} stroke={cm.color} strokeWidth={isSel?2:1.5}/>
                  <text y={sz+13} textAnchor="middle" style={{fill:isSel?"#E8F0FF":"#4A5878",fontSize:isSel?11:9.5,fontFamily:"inherit",fontWeight:isSel?600:400,pointerEvents:"none"}}>
                    {m.name.length>22?m.name.slice(0,20)+"…":m.name}
                  </text>
                </g>
              );
            })}
          </svg>
          {/* Legend */}
          <div style={{position:"absolute",bottom:28,left:16,display:"flex",gap:10,flexWrap:"wrap"}}>
            {Object.entries(CATEGORY_META).map(([k,v])=>(
              <div key={k} style={{display:"flex",alignItems:"center",gap:5}}>
                <div style={{width:7,height:7,borderRadius:"50%",background:v.color}}/>
                <span style={{color:"#2A3450",fontSize:9}}>{v.label}</span>
              </div>
            ))}
          </div>
          <div style={{position:"absolute",bottom:10,left:0,right:0,textAlign:"center",color:"#1E2840",fontSize:9}}>
            {displayed.length} / {models.length} models · click to select · click again to deselect
          </div>
        </div>

        {/* Detail panel */}
        {selected && (
          <div style={{width:340,borderLeft:"1px solid #141828",background:"#08090F",overflowY:"auto",padding:"18px 20px",flexShrink:0}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:14}}>
              <span style={{background:meta.color+"1A",color:meta.color,padding:"2px 9px",borderRadius:2,fontSize:9,letterSpacing:"0.1em",textTransform:"uppercase"}}>{meta.glyph} {meta.label}</span>
              <button onClick={()=>setSelected(null)} style={{background:"none",border:"none",color:"#333",cursor:"pointer",fontSize:15}}>✕</button>
            </div>
            <h3 style={{margin:"0 0 14px",color:"#F0F4FF",fontSize:14,fontWeight:600,lineHeight:1.4}}>{selected.name}</h3>
            {[
              ["First Principle", selected.first_principle],
              ["Derived From", selected.derived_from],
              ["When It Applies", selected.when_applies],
              ["Breaks Down When", selected.when_breaks_down],
            ].map(([label,val])=>(
              <div key={label} style={{marginBottom:12}}>
                <div style={{color:"#2A3450",fontSize:8.5,letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:4}}>{label}</div>
                <div style={{color:"#7A8AAA",fontSize:11,lineHeight:1.65}}>{val}</div>
              </div>
            ))}
            <div style={{marginBottom:14}}>
              <div style={{color:meta.color,fontSize:8.5,letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:4}}>AI / Architecture Application</div>
              <div style={{color:"#C8D8F0",fontSize:11,lineHeight:1.7,borderLeft:`2px solid ${meta.color}55`,paddingLeft:10,background:meta.color+"08",padding:"8px 10px",borderRadius:1}}>{selected.ai_application}</div>
            </div>
            {(selected.tags||[]).length>0 && (
              <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:14}}>
                {selected.tags.map(t=><span key={t} style={{background:"#0F1220",color:"#2A3450",padding:"2px 7px",borderRadius:2,fontSize:9}}>#{t}</span>)}
              </div>
            )}
            {(()=>{
              const conns=(selected.connects_to||[]).map(id=>models.find(m=>m.id===id)).filter(Boolean);
              if(!conns.length) return null;
              return (
                <div>
                  <div style={{color:"#2A3450",fontSize:8.5,letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:8}}>Connects To</div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                    {conns.map(c=>{const cm=CATEGORY_META[c.category]||{};return(
                      <button key={c.id} onClick={()=>setSelected(c)} style={{background:cm.color+"12",border:`1px solid ${cm.color}33`,color:cm.color,padding:"4px 9px",borderRadius:2,fontSize:10,cursor:"pointer",fontFamily:"inherit"}}>{c.name}</button>
                    );})}
                  </div>
                </div>
              );
            })()}
          </div>
        )}
      </div>
      {showSettings && <SettingsModal onClose={()=>setShowSettings(false)} onLoad={m=>{setModels(m);setShowSettings(false);}} />}
    </div>
  );
}
